function userModalHtml(){const u=state.editId?getUserById(state.editId):{fullName:'',username:'',password:'123',role:'user',jobTitle:'',college:'كلية الصيدلة',department:'الكل',phone:'',email:'',nationalId:'',isActive:true,permissions:[]}; return `<div class="modal-backdrop" onclick="closeIfBackdrop(event)"><div class="modal"><div class="modal-header"><div class="panel-title">${state.editId?'تعديل مستخدم':'إضافة مستخدم'}</div><button class="btn btn-secondary btn-sm" onclick="closeModal()">إغلاق</button></div><div class="modal-body"><div class="form-grid-3"><div><label class="label">الاسم</label><input id="user-fullName" class="input" value="${u.fullName}"></div><div><label class="label">اسم المستخدم</label><input id="user-username" class="input" value="${u.username}"></div><div><label class="label">كلمة المرور</label><input id="user-password" class="input" value="${u.password}"></div><div><label class="label">النوع</label><select id="user-role" class="select"><option value="admin" ${u.role==='admin'?'selected':''}>Admin</option><option value="user" ${u.role==='user'?'selected':''}>User</option></select></div><div><label class="label">المسمى</label><input id="user-jobTitle" class="input" value="${u.jobTitle}"></div><div><label class="label">الكلية/الإدارة</label><select id="user-college" class="select"><option value="إدارة التجهيزات" ${u.college==='إدارة التجهيزات'?'selected':''}>إدارة التجهيزات</option>${collegeOptions(u.college,false)}</select></div><div><label class="label">القسم</label><select id="user-department" class="select">${userDepartmentOptions(u.department||'الكل')}</select></div><div><label class="label">الهاتف</label><input id="user-phone" class="input" value="${u.phone}"></div><div><label class="label">البريد</label><input id="user-email" class="input" value="${u.email}"></div><div><label class="label">الهوية</label><input id="user-nationalId" class="input" value="${u.nationalId}"></div><div><label class="checkbox"><input id="user-active" type="checkbox" ${u.isActive?'checked':''}> نشط</label></div><div class="full"><label class="label">الصلاحيات التشغيلية</label><div class="permissions-grid">${PERMISSIONS.filter(p=>!p.key.startsWith('report_')).map(p=>`<label class="checkbox"><input class="perm-box" type="checkbox" value="${p.key}" ${(u.permissions||[]).includes(p.key)||u.role==='admin'?'checked':''}>${p.label}</label>`).join('')}</div></div><div class="full"><label class="label">أنواع التقارير المسموح بها</label><div class="permissions-grid">${PERMISSIONS.filter(p=>p.key.startsWith('report_')).map(p=>`<label class="checkbox"><input class="perm-box" type="checkbox" value="${p.key}" ${(u.permissions||[]).includes(p.key)||u.role==='admin'?'checked':''}>${p.label}</label>`).join('')}</div></div></div></div><div class="modal-footer"><button class="btn btn-secondary" onclick="closeModal()">إلغاء</button><button class="btn btn-primary" onclick="saveUser()">حفظ</button></div></div></div>`}
function reportHtml(data){return `<!DOCTYPE html><html lang="ar" dir="rtl"><head><meta charset="UTF-8"><title>${data.title}</title><style>body{font-family:Tahoma,Arial,sans-serif;direction:rtl;padding:24px;color:#111144}.report-header{display:flex;justify-content:space-between;align-items:center;border:1px solid #d9e2ef;border-radius:18px;padding:18px 20px;margin-bottom:18px;background:linear-gradient(135deg,#f7fbff,#eef7f4)}.logo-mark{width:72px;height:72px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:30px;background:linear-gradient(135deg,#0a8e6e,#4056e3);color:#fff;font-weight:bold}.report-header h1{font-size:22px;margin:0 0 8px}.report-header p{margin:0;line-height:1.8;color:#555}.meta-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin:0 0 18px}.meta-card{border:1px solid #d9e2ef;border-radius:14px;padding:10px 12px;background:#fff}.meta-card strong{display:block;margin-bottom:4px}table{width:100%;border-collapse:collapse;font-size:12px}th,td{border:1px solid #999;padding:8px;text-align:right;vertical-align:top}th{background:#f2f2f2}.footer{margin-top:14px;font-size:11px;color:#555}@media print{body{padding:8px}}</style></head><body><div class="report-header"><div><h1>${data.title}</h1><p>جامعة طيبة</p><p>نظام إدارة القطاعات التعليمية</p></div><div class="logo-mark">T</div></div><div class="meta-grid"><div class="meta-card"><strong>تاريخ الإنشاء</strong>${formatDateTime(nowLocalString())}</div><div class="meta-card"><strong>عدد السجلات</strong>${data.rows.length}</div><div class="meta-card"><strong>مستخرج التقرير</strong>${state.currentUser?.fullName||'—'}</div><div class="meta-card"><strong>النطاق</strong>${isCentral()?'جامعة طيبة':state.currentUser.college}</div></div><table><thead><tr>${data.headers.map(h=>`<th>${h}</th>`).join('')}</tr></thead><tbody>${data.rows.length?data.rows.map(r=>`<tr>${r.map(c=>`<td>${String(c??'—').replace(/<[^>]*>/g,'')}</td>`).join('')}</tr>`).join(''):`<tr><td colspan="${data.headers.length}">لا توجد بيانات</td></tr>`}</tbody></table><div class="footer">ملاحظة: تم إنشاء هذا التقرير من نظام جامعة طيبة لإدارة القطاعات التعليمية.</div></body></html>`}
function openPrint(data){const w=window.open('','_blank'); if(!w)return alert('اسمح بالنوافذ المنبثقة'); w.document.write(reportHtml(data)); w.document.close(); setTimeout(()=>w.print(),300)}
