function printNeeds(){openPrint({title:'تقرير طلبات الاحتياج',headers:['رقم الطلب','الكلية','القسم','الصنف','الكمية','الوحدة','الحالة','صاحب الإجراء'],rows:filteredNeeds().map(r=>[r.requestNo,r.college,r.section,r.itemNameAr||r.itemNameEn,r.qty,r.unit,statusText(r.status),actorName(r.createdBy)])})}
function exportExcel(data,filename){if(typeof XLSX==='undefined')return alert('مكتبة Excel غير محملة. تأكد من الاتصال بالإنترنت.'); const cleanRows=data.rows.map(r=>r.map(c=>String(c??'—').replace(/<[^>]*>/g,''))); const aoa=[['جامعة طيبة'],['نظام إدارة القطاعات التعليمية'],[data.title],['تاريخ الإنشاء',formatDateTime(nowLocalString())],['مستخرج التقرير',state.currentUser?.fullName||'—'],['النطاق',isCentral()?'جامعة طيبة':state.currentUser.college],[],data.headers,...cleanRows]; const ws=XLSX.utils.aoa_to_sheet(aoa); ws['!merges']=[{s:{r:0,c:0},e:{r:0,c:Math.max(data.headers.length-1,1)}},{s:{r:1,c:0},e:{r:1,c:Math.max(data.headers.length-1,1)}},{s:{r:2,c:0},e:{r:2,c:Math.max(data.headers.length-1,1)}}]; ws['!autofilter']={ref:XLSX.utils.encode_range({s:{r:7,c:0},e:{r:Math.max(7+cleanRows.length,7),c:data.headers.length-1}})}; ws['!cols']=data.headers.map((h,idx)=>({wch: Math.max(String(h).length+6,...cleanRows.map(r=>String(r[idx]||'').length+4),18)})); const wb=XLSX.utils.book_new(); XLSX.utils.book_append_sheet(wb,ws,'Report'); XLSX.writeFile(wb,filename)}
function exportCurrentExcel(){const d=reportData();exportExcel(d,'taibah-report.xlsx')}
function exportFullExcel(){exportExcel({title:'تقرير إداري شامل للمتابعة المركزية',headers:['المؤشر','القيمة'],rows:Object.entries(metrics()).map(([k,v])=>[k,v])},'central-monitoring-report.xlsx')}
function exportNeeds(){exportExcel({title:'تقرير طلبات الاحتياج',headers:['رقم الطلب','الكلية','القسم','العربي','English','الكمية','الوحدة','الحالة','صاحب الإجراء','راجعه'],rows:filteredNeeds().map(r=>[r.requestNo,r.college,r.section,r.itemNameAr,r.itemNameEn,r.qty,r.unit,statusText(r.status),actorName(r.createdBy),actorName(r.reviewedBy)])},'needs-report.xlsx')}

